pub fn all_models() -> &'static [ModelMetadata] {
    ALL_MODELS
}

pub fn lookup(provider: &str, id: &str) -> Option<&'static ModelMetadata> {
    match provider {
        "anthropic" => anthropic::lookup(id),
        "azure" => azure::lookup(id),
        "chatgpt" => chatgpt::lookup(id),
        "cohere" => cohere::lookup(id),
        "copilot" => copilot::lookup(id),
        "deepseek" => deepseek::lookup(id),
        "galadriel" => galadriel::lookup(id),
        "gemini" => gemini::lookup(id),
        "groq" => groq::lookup(id),
        "huggingface" => huggingface::lookup(id),
        "hyperbolic" => hyperbolic::lookup(id),
        "llamafile" => llamafile::lookup(id),
        "minimax" => minimax::lookup(id),
        "mistral" => mistral::lookup(id),
        "moonshot" => moonshot::lookup(id),
        "ollama" => ollama::lookup(id),
        "openai" => openai::lookup(id),
        "openrouter" => openrouter::lookup(id),
        "perplexity" => perplexity::lookup(id),
        "together" => together::lookup(id),
        "voyageai" => voyageai::lookup(id),
        "xai" => xai::lookup(id),
        "zai" => zai::lookup(id),
        _ => None,
    }
}
